from board import Board

def test_board_initialization():
    board = Board()
    expected_pieces = [
        (0, 1), (0, 3), (0, 5), (0, 7),
        (2, 1), (2, 3), (2, 5), (2, 7),
        (5, 0), (5, 2), (5, 4), (5, 6),
        (7, 0), (7, 2), (7, 4), (7, 6)
    ]
    actual_pieces = [(i, j) for i in range(8) for j in range(8) if board.board[i][j] is not None]
    assert expected_pieces == actual_pieces

def test_move_piece():
    board = Board()
    start = (0, 1)
    end = (2, 3)
    assert board.move_piece(start, end) == True
    assert board.board[2][3].position == (2, 3)
